#!/bin/bash

# Build the LaTeX document specified as the first argument

# First, get the word count and save it to wordcount.txt
texcount -nobib $1.tex | awk -F: ' $1 == "Words in text" {print $2}' > $1-wordcount.txt

# clean up auxiliary files generated by LaTeX
rm -f $1.aux $1.bbl $1.blg $1.log $1.out $1.toc

# Generate the PDF (first pass) - use nonstopmode to continue past errors
pdflatex -interaction=nonstopmode $1.tex

# Run BibTeX to handle references (needs the .aux file from first pdflatex run)
bibtex $1

# Run pdflatex more times to ensure all references are updated
pdflatex -interaction=nonstopmode $1.tex
pdflatex -interaction=nonstopmode $1.tex
pdflatex -interaction=nonstopmode $1.tex
pdflatex -interaction=nonstopmode $1.tex